'use strict';

const fs = require('fs');
const path = require('path');

const root = path.resolve(__dirname, '..');
const args = new Set(process.argv.slice(2));
const checkOnly = args.has('--check');

const bundles = [
 {
  target: 'src/renderer/scripts/popup/06-v16-capabilities.js',
  parts: [
   'src/renderer/scripts/popup/parts/v16-capabilities/01-state-and-shared.jsfrag',
   'src/renderer/scripts/popup/parts/v16-capabilities/02-journal-and-private-snapshot.jsfrag',
   'src/renderer/scripts/popup/parts/v16-capabilities/03-capability-shell-and-settings.jsfrag',
   'src/renderer/scripts/popup/parts/v16-capabilities/04-trade-journal-and-ledger.jsfrag',
   'src/renderer/scripts/popup/parts/v16-capabilities/05-live-analytics-and-setup.jsfrag',
   'src/renderer/scripts/popup/parts/v16-capabilities/06-security-and-order-preview.jsfrag',
   'src/renderer/scripts/popup/parts/v16-capabilities/07-live-order-actions.jsfrag',
   'src/renderer/scripts/popup/parts/v16-capabilities/08-panes-bindings-init-and-var.jsfrag',
  ],
 },
 {
  target: 'src/renderer/scripts/popup/07-chart-workspace.js',
  parts: [
   'src/renderer/scripts/popup/parts/chart-workspace/01-state-and-fetch.jsfrag',
   'src/renderer/scripts/popup/parts/chart-workspace/02-model-and-order-context.jsfrag',
   'src/renderer/scripts/popup/parts/chart-workspace/03-render-shells.jsfrag',
   'src/renderer/scripts/popup/parts/chart-workspace/04-surface-events.jsfrag',
   'src/renderer/scripts/popup/parts/chart-workspace/05-public-api.jsfrag',
  ],
 },
 {
  target: 'src/renderer/scripts/popup/08-options-workspace.js',
  parts: [
   'src/renderer/scripts/popup/parts/options-workspace/01-state-and-normalize.jsfrag',
   'src/renderer/scripts/popup/parts/options-workspace/02-data-refresh-and-health.jsfrag',
   'src/renderer/scripts/popup/parts/options-workspace/03-chain-builder-analyzer-render.jsfrag',
   'src/renderer/scripts/popup/parts/options-workspace/04-straddle-and-skew-render.jsfrag',
   'src/renderer/scripts/popup/parts/options-workspace/05-events-and-public-api.jsfrag',
  ],
 },
];

function read(relativePath) {
 return fs.readFileSync(path.join(root, relativePath), 'utf8').replace(/\r\n/g, '\n');
}

function write(relativePath, content) {
 fs.mkdirSync(path.dirname(path.join(root, relativePath)), { recursive: true });
 fs.writeFileSync(path.join(root, relativePath), content.replace(/\n/g, '\r\n'), 'utf8');
}

function buildBundle(bundle) {
 const body = bundle.parts.map(part => {
  if (!fs.existsSync(path.join(root, part))) {
   throw new Error(`Missing renderer bundle part: ${part}`);
  }
  return read(part).trimEnd();
 }).join('\n\n');
 return [
  '// This file is generated by scripts/sync-renderer-bundles.js.',
  '// Edit the feature-sized files under src/renderer/scripts/popup/parts instead.',
  body,
  '',
 ].join('\n');
}

let changed = false;
for (const bundle of bundles) {
 const expected = buildBundle(bundle);
 const current = fs.existsSync(path.join(root, bundle.target)) ? read(bundle.target) : '';
 if (current !== expected) {
  changed = true;
  if (checkOnly) {
   console.error(`Renderer bundle is out of sync: ${bundle.target}`);
  } else {
   write(bundle.target, expected);
   console.log(`Synced ${bundle.target}`);
  }
 }
}

if (checkOnly && changed) {
 console.error('Run: npm run build:renderer');
 process.exit(1);
}

if (!changed) {
 console.log('Renderer bundles are in sync.');
}
